const data = $input.first().json;
const errors = [];
for (const field of ['title', 'description', 'source_id']) {
  if (!data[field]) errors.push(`${field} là bắt buộc`);
}
if (data.price !== undefined && Number(data.price) <= 0) errors.push('price phải dương');
if (errors.length) throw new Error(`Dữ liệu Facebook không hợp lệ: ${errors.join(', ')}`);
return [{ json: data }];

const data = $input.first().json;
const price = data.price ? `Giá tham khảo: ${Number(data.price).toLocaleString('vi-VN')} VND` : '';
const bullets = [
  data.category ? `Phù hợp nhóm: ${data.category}` : '',
  price,
  'Tư vấn theo trình độ, ngân sách và lối chơi của bạn.'
].filter(Boolean);
const message = [
  `Bạn đang tìm ${data.title}?`,
  '',
  data.description,
  '',
  'Điểm đáng chú ý:',
  ...bullets.map(b => `• ${b}`),
  '',
  'Cần BongBanViet tư vấn setup phù hợp? Nhắn tin hoặc xem chi tiết tại link bên dưới.',
  data.product_url || '',
  '',
  '#BongBanViet #BóngBàn #TableTennis #TưVấnBóngBàn'
].filter(Boolean).join('\n');
return [{ json: { ...data, facebook_message: message } }];

const data = $input.first().json;
// Sử dụng image_url từ source data.
// Nếu cần resize/watermark, thay thế bằng URL CDN đã xử lý.
const imageUrl = data.image_url || '';
return [{ json: { ...data, prepared_image_url: imageUrl } }];

const result = $input.first().json;
const data = $('Generate Facebook Content').first().json;
const payload = {
  channel: 'facebook',
  ok: true,
  post_id: result.post_id || result.id || '',
  source_id: data.source_id || '',
  title: data.title || '',
  saved_at: new Date().toISOString()
};
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
if (webhook) {
  const res = await fetch(webhook, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });
  if (!res.ok) console.warn('Result webhook failed', res.status);
}
return [{ json: { ...payload, notified: !!webhook } }];

const error = $execution.error || {};
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
const payload = {
  channel: 'facebook',
  ok: false,
  error: error.message || 'Unknown error',
  node: error.node?.name || '',
  time: new Date().toISOString()
};
if (webhook) {
  await fetch(webhook, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  }).catch(() => {});
}
return [{ json: payload }];
